return items.map((item) => {
  const j = item.json;
  const analytics = j.analytics_context || {};
  const crm = j.crm_context || {};
  const social = j.social_accounts || {};
  const metrics = Array.isArray(analytics.metrics) ? analytics.metrics : [];
  const strongestChannel = metrics.slice().sort((a, b) => (b.leads || 0) - (a.leads || 0))[0]?.channel || "linkedin";
  const audience = analytics.audience_segments?.[0] || "small businesses with fragmented operations";
  return {
    json: {
      ...j,
      current_workflow: "WF024 Campaign Data Aggregation Workflow",
      workflow_category: "marketing",
      workflow_step_detail: "Normalize analytics, CRM, social readiness, and campaign inputs into a campaign planning package.",
      target_agent: j.target_agent || "marketing-sales-agent",
      event_type: j.event_type || "campaign_review",
      campaign_package: {
        campaign_id: analytics.campaign_id || j.campaign_id || j.id,
        strongest_channel: strongestChannel,
        audience,
        intent_signals: crm.intent_signals || [],
        objections: crm.objections || [],
        social_accounts: social,
        metrics,
      },
      n8n_owns_execution: true,
      openclaw_external_access: false,
    },
  };
});

// Marketing Intelligence Trigger Workflow
return items.map((item) => {
  const j = item.json;
  const campaign = j.campaign_package || {};
  const angles = [
    "turn disconnected manual work into managed AI operations",
    "ship safer automations with human approval gates",
    "connect support, sales, inventory, and reporting workflows",
  ];
  const variants = angles.map((angle, index) => ({
    id: `${j.id || $execution.id}-variant-${index + 1}`,
    channel: index === 0 ? campaign.strongest_channel || "linkedin" : index === 1 ? "email" : "website",
    hook: angle,
    draft: `Syntrixa helps ${campaign.audience || "small teams"} ${angle}. Book an AI operations audit to map the next workflow.`,
    status: "staged_for_review",
  }));
  return {
    json: {
      ...j,
      current_workflow: "WF026 Marketing Intelligence Trigger Workflow",
      workflow_category: "marketing",
      workflow_step_detail: "Generate channel strategy, content variants, and OpenClaw marketing reasoning context.",
      target_agent: "marketing-sales-agent",
      event_type: "campaign_review",
      campaign_strategy: {
        objective: j.payload?.objective || "generate qualified Syntrixa audit conversations",
        audience: campaign.audience,
        primary_channel: campaign.strongest_channel || "linkedin",
        angles,
        required_human_approval: true,
      },
      content_variants: variants,
      context_package: {
        package_id: j.id || $execution.id,
        source_workflow: "WF026 Marketing Intelligence Trigger Workflow",
        subject_refs: { campaign_id: campaign.campaign_id || j.id },
        constraints: { minimal_context: true, no_raw_secrets: true },
        analytics_context: j.analytics_context,
        crm_context: j.crm_context,
        campaign_strategy: {
          objective: j.payload?.objective || "generate qualified Syntrixa audit conversations",
          primary_channel: campaign.strongest_channel || "linkedin",
        },
      },
      n8n_owns_execution: true,
      openclaw_external_access: false,
    },
  };
});

