      ...j,
      current_workflow: "WF027 Campaign Proposal Execution Workflow",
      workflow_category: "marketing",
      workflow_step_detail: "Stage approved campaign execution actions for social, email, and website channels.",
      campaign_execution_plan: {
        approval_required: true,
        execution_mode: Object.values(connectorState).some((item) => item.connected) ? "credential_ready_staging" : "local_staging_only",
        connectorState,
        content_variants: j.content_variants || [],
        next_steps: [
